//-------------- Countdown ------------------

var CDown = function() {
    this.state=0;// if initialized
    this.counts=[];// array holding countdown date objects and id to print to {d:new Date(2013,11,18,18,54,36), id:"countbox1"}
    this.interval=null;// setInterval object
}

CDown.prototype = {
    init: function(){
        this.state=1;
        var self=this;
        this.interval=window.setInterval(function(){self.tick();}, 1000);
    },
    add: function(date,id){
        var nowd=new Date();

        //set this to the number of hours offset from UTC
        tzOffset = -6;

        dx = date.toGMTString();
        dx = dx.substr(0,dx.length -3);
        tzCurrent=(date.getTimezoneOffset()/60)*-2;
        date.setTime(Date.parse(dx))
        date.setHours(date.getHours() + tzCurrent - tzOffset);

        this.counts.push({d:date,id:id});
        this.tick();
        if(this.state==0) this.init();
    },
    expire: function(idxs){
        for(var x in idxs) {
            this.display(this.counts[idxs[x]], "This event has ended.");
            this.counts.splice(idxs[x], 1);
        }
    },
    format: function(r){
        var out="";
        if(r.w != 0){out += r.w +" "+((r.w==1)?"week":"weeks")+", ";}
        if(r.d != 0){out += r.d +" "+((r.d==1)?"day":"days")+", ";}
        if(r.h != 0){out += r.h +" "+((r.h==1)?"hour":"hours")+", ";}
        out += r.m +" "+((r.m==1)?"min":"mins")+", ";
        out += r.s +" "+((r.s==1)?"sec":"secs")+", ";

        return out.substr(0,out.length-2);
    },
    math: function(work){
        var y=w=d=h=m=s=ms=0;

        ms=(""+((work%1000)+1000)).substr(1,3);
        work=Math.floor(work/1000);//kill the "milliseconds" so just secs

        y=Math.floor(work/31536000);//years (no leapyear support)
        w=Math.floor(work/604800);//weeks
        work=work%604800;

        d=Math.floor(work/86400);//days
        work=work%86400;

        h=Math.floor(work/3600);//hours
        work=work%3600;

        m=Math.floor(work/60);//minutes
        work=work%60;

        s=Math.floor(work);//seconds

        return {y:y,w:w,d:d,h:h,m:m,s:s,ms:ms};
    },
    tick: function(){
        var now=(new Date()).getTime(),
            expired=[],cnt=0,amount=0;

        if(this.counts)
        for(var idx=0,n=this.counts.length; idx<n; ++idx){
            cnt=this.counts[idx];
            amount=cnt.d.getTime()-now;//calc milliseconds between dates

            // if time is already past
            if(amount<0){
                expired.push(idx);
            }
            // date is still good
            else{
                this.display(cnt, this.format(this.math(amount)));
            }
        }

        // deal with any expired
        if(expired.length>0) this.expire(expired);

        // if no active counts, stop updating
        if(this.counts.length==0) window.clearTimeout(this.interval);

    },
    display: function (cnt, msg) {
        var selection = document.getElementById(cnt.id);
        if (selection !== null) {
            selection.innerHTML = msg;
        }
    }
};

//------------------------------------------

window.onload=function(){
    GetClock();
    setInterval(GetClock,1000);
};

//-------------- Clock ------------------

function GetClock(){
   var tzOffset = -6;

   var d=new Date();
   var dx=d.toGMTString();
   dx=dx.substr(0,dx.length -3);
   d.setTime(Date.parse(dx))
   d.setHours(d.getHours()+tzOffset);
   var nhour=d.getHours(),nmin=d.getMinutes(),ap;
   if(nhour==0){ap=" AM";nhour=12;}
   else if(nhour<12){ap=" AM";}
   else if(nhour==12){ap=" PM";}
   else if(nhour>12){ap=" PM";nhour-=12;}

   if(nmin<=9) nmin="0"+nmin;

   document.getElementById('clockbox').innerHTML=""+nhour+":"+nmin+ap+"";
}

//----------------------------------------

window.onload=function(){
   GetClock();
   setInterval(GetClock,1000);

   var cdown = new CDown();
   cdown.add(new Date(2016,6,1,0,00,00), "countbox1");
};
