// offcanvas navbar

function openSidebar() {
    document.getElementById("offcanvas").className = "admin-sidebar bg-light border-right position-relative h-100";
    document.getElementById("offcanvas-arrow").className = "position-absolute";
}

function closeSidebar() {
    document.getElementById("offcanvas").className = "admin-sidebar bg-light border-right position-relative d-none";
    document.getElementById("offcanvas-arrow").className = "position-absolute d-none";
}
